const query = $input.first().json.query || {};

const decision    = query.decision    || '';
const staffName   = decodeURIComponent(query.staffName   || '');
const submittedAt = decodeURIComponent(query.submittedAt || '');

if (!['Approved', 'Rejected'].includes(decision)) {
  throw new Error('Invalid decision. Must be Approved or Rejected.');
}
if (!staffName || !submittedAt) {
  throw new Error('Missing staffName or submittedAt parameter.');
}

return [{
  json: {
    decision,
    staffName,
    submittedAt,
    claimStatus: decision
  }
}];

// Read original request
const parsed = $('Parse Approval Request').first().json;
const targetTimestamp = parsed.submittedAt;

// Search ALL rows to find the matching claim
const allRows = $input.all();
const matchedRow = allRows.find(item => item.json.submittedAt === targetTimestamp);

if (!matchedRow) {
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Claim Not Found</title></head><body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center"><div style="max-width:460px;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)"><div style="font-size:72px;margin-bottom:16px">❓</div><h1 style="color:#f59e0b;font-size:26px;margin:0 0 12px">Claim Not Found</h1><p style="color:#555;font-size:15px">We couldn't find this OPD claim in the database.</p></div></body></html>`;
  return [{ json: { html, locked: true } }];
}

const currentStatus = (matchedRow.json.claimStatus || '').trim();

if (currentStatus === 'Approved' || currentStatus === 'Rejected') {
  const emoji = currentStatus === 'Approved' ? '✅' : '❌';
  const color = currentStatus === 'Approved' ? '#10b981' : '#ef4444';
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><title>Already Processed</title></head><body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center;box-sizing:border-box"><div style="max-width:460px;width:100%;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)"><div style="font-size:72px;margin-bottom:16px">🔒</div><h1 style="color:#6366f1;font-size:24px;margin:0 0 12px">Already Processed</h1><p style="color:#555;font-size:15px;line-height:1.6;margin:0 0 24px">This OPD claim has already been <strong>${currentStatus}</strong> ${emoji} and cannot be changed.</p><div style="background:#f3f4f6;border-radius:10px;padding:16px 20px;text-align:left"><p style="margin:4px 0;font-size:13px;color:#444">👤 <strong>Staff:</strong> ${parsed.staffName}</p><p style="margin:4px 0;font-size:13px;color:${color}">🏷 <strong>Final Status:</strong> ${currentStatus} ${emoji}</p></div><p style="margin-top:28px;color:#aaa;font-size:12px">No further action is needed.</p></div></body></html>`;
  return [{ json: { html, locked: true } }];
}

// Not decided — proceed
return [{ json: { ...parsed, locked: false } }];

// Re-read decision data from the earlier node (Sheets update wipes the fields)
const lockData  = $('Check If Already Decided').first().json;
const decision  = lockData.decision  || '';
const staffName = lockData.staffName || '';
return [{ json: { decision, staffName, locked: false } }];

const data      = $input.first().json;
const locked    = data.locked ?? false;
const decision  = data.decision  || '';
const staffName = data.staffName || '';

// If locked (already processed), html is already built
if (locked && data.html) {
  return [{ json: { html: data.html } }];
}

const isApproved = decision === 'Approved';
const emoji   = isApproved ? '✅' : '❌';
const color   = isApproved ? '#10b981' : '#ef4444';
const bgColor = isApproved ? '#ecfdf5'  : '#fef2f2';
const title   = isApproved ? 'OPD Claim Approved!' : 'OPD Claim Rejected';
const message = isApproved
  ? `The OPD medical claim for <strong>${staffName}</strong> has been <strong>approved</strong> for reimbursement.`
  : `The OPD medical claim for <strong>${staffName}</strong> has been <strong>rejected</strong>.`;

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"><title>${title}</title></head>
<body style="font-family:Arial,sans-serif;background:#f5f5f5;margin:0;padding:40px;min-height:100vh;display:flex;align-items:center;justify-content:center;box-sizing:border-box">
  <div style="max-width:460px;width:100%;background:white;border-radius:16px;padding:48px 36px;text-align:center;box-shadow:0 8px 32px rgba(0,0,0,0.1)">
    <div style="font-size:72px;margin-bottom:16px">${emoji}</div>
    <h1 style="color:${color};font-size:26px;margin:0 0 12px">${title}</h1>
    <p style="color:#555;font-size:15px;line-height:1.6;margin:0 0 24px">${message}</p>
    <div style="background:${bgColor};border:1px solid ${color}44;border-radius:10px;padding:16px 20px;text-align:left">
      <p style="margin:4px 0;font-size:13px;color:#444">👤 <strong>Staff:</strong> ${staffName}</p>
      <p style="margin:4px 0;font-size:13px;color:#444">🏷 <strong>Decision:</strong> ${decision}</p>
    </div>
    <p style="margin-top:28px;color:#aaa;font-size:12px">The OPD Claims Database has been updated automatically.</p>
  </div>
</body></html>`;

return [{ json: { html } }];
